/**
 * @summary Aggregate audit logs by action type, status, and method
 */
export const getClaudeAuditLogsAggregateUrl = (
  params?: ClaudeAuditLogsAggregateParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/claude/audit/logs/aggregate?${stringifiedParams}`
    : `/api/claude/audit/logs/aggregate`;
};

